function Nav({ page, setPage }) {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);
  const links = ["Home","Activities","About","Team"];
  return (
    <nav style={{
      position:"fixed", top:0, left:0, right:0, zIndex:1000,
      background: scrolled ? "rgba(4,6,16,0.97)" : "transparent",
      backdropFilter: scrolled ? "blur(12px)" : "none",
      borderBottom: scrolled ? "1px solid rgba(59,130,246,0.15)" : "none",
      transition:"all .3s",
      display:"flex", alignItems:"center", justifyContent:"space-between",
      padding:"0 2.5rem", height:64,
    }}>
      <div style={{display:"flex", alignItems:"center", gap:"1rem", cursor:"pointer"}}
           onClick={()=>setPage("Home")}>
        <img src={NS_LOGO} alt="NexaSphere" style={{height:38,width:38,objectFit:"contain"}} />
        <span style={{
          fontFamily:"'Orbitron',sans-serif", fontSize:"1.05rem", fontWeight:700,
          background:"linear-gradient(90deg,#38bdf8,#818cf8)",
          WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent",
          letterSpacing:".06em"
        }}>NexaSphere</span>
      </div>
      <div style={{display:"flex", alignItems:"center", gap:"0.2rem"}}>
        {links.map(l => (
          <button key={l} onClick={()=>setPage(l)} style={{
            background: page===l ? "rgba(56,189,248,0.12)" : "transparent",
            border: page===l ? "1px solid rgba(56,189,248,0.35)" : "1px solid transparent",
            color: page===l ? "#38bdf8" : "#94a3b8",
            borderRadius:6, padding:"6px 14px",
            fontFamily:"'Orbitron',sans-serif",
            fontSize:".68rem", letterSpacing:".1em",
            cursor:"pointer", transition:"all .2s",
          }}>{l}</button>
        ))}
      </div>
      <img src={GL_LOGO} alt="GL Bajaj" style={{height:34,objectFit:"contain",filter:"brightness(1.1)"}} />
    </nav>
  );
}

